// BeadCancelStore reads/writes the cancel markers on a bead's Extra map.
// Implemented by *bead.Store. ADR-022 §Cancel SLA: the worker polls
// IsCancelRequested mid-attempt and on a positive read writes
// MarkCancelHonored before aborting at the next safe point.
type BeadCancelStore interface {
	IsCancelRequested(id string) (bool, error)
	MarkCancelHonored(id string) error
}

// CancelPollInterval is how often the worker checks for an operator cancel
// while an agent attempt is in flight. ADR-022 §Cancel SLA names 10s as the
// default. Exposed as a variable so tests can override it.
var CancelPollInterval = 10 * time.Second

// RunStateRefreshInterval controls how often execute-bead refreshes its
// per-attempt liveness record while the agent harness is running. Exposed as a
// variable so tests can shorten it without slowing production attempts.
var RunStateRefreshInterval = 10 * time.Second

// ExecuteBeadRuntime carries the non-durable plumbing for an execute-bead
// run: per-invocation intent (FromRev, PromptFile, WorkerID) and
// non-serializable injection seams (BeadEvents, Service, AgentRunner).
// Durable knobs (Harness, Model, Provider, Effort,
// ContextBudget, MirrorCfg) live on config.ResolvedConfig and are passed
// via ExecuteBeadWithConfig's rcfg argument.
//
// See SD-024 / TD-024 §Runtime structs and §Stage 3.
type ExecuteBeadRuntime struct {
	FromRev         string // base git revision (default: HEAD)
	PromptFile      string // override prompt file (auto-generated if empty)
	Output          io.Writer
	WorkerID        string // from DDX_WORKER_ID env or caller
	BeadEvents      BeadEventAppender
	BeadCancel      BeadCancelStore // optional: enables operator-cancel mid-attempt poll
	ResourceChecker ExecutionResourceChecker
	Service         agentlib.FizeauService
	AgentRunner     AgentRunner
	AttemptBackend  AttemptBackend
	// RateLimitMaxWait bounds the per-bead total wait spent on rate-limit
	// retries (ddx-c6e3db02 RateLimitRetryContract / TD-031 §8.4). Zero uses
	// RateLimitRetryDefaultBudget (5 min). Negative disables the wrapper —
	// rate-limit responses fall through to the standard execution_failed path.
	RateLimitMaxWait time.Duration

	if slotScoped {
		prior = CountPriorReviewErrorsForSlot(in.Store, in.Bead.ID, report.ResultRev, reviewerIndex)
	}
	attemptCount := prior + 1
	maxRetries := in.Rcfg.ReviewMaxRetries()
	if maxRetries <= 0 {
		maxRetries = DefaultReviewMaxRetries
	}
	errSummary := EventBodySummary{
		InputBytes:  0,
		OutputBytes: 0,
	}
	if reviewRes != nil {
		errSummary = EventBodySummary{
			Harness:     reviewRes.ReviewerHarness,
			Model:       reviewRes.ReviewerModel,
			InputBytes:  reviewRes.InputBytes,
			OutputBytes: reviewRes.OutputBytes,
			ElapsedMS:   reviewRes.DurationMS,
		}
	}
	// reviewer_unavailable is a routing/infra failure, not a quality verdict.
	// Never terminal-park on it — always hold open so the loop can retry.
	reviewerUnavailable := class == evidence.OutcomeReviewReviewerUnavailable
	if attemptCount >= maxRetries && !reviewerUnavailable {
		body := ReviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error())
		if slotScoped {
			body = ReviewErrorEventBodyForSlot(class, attemptCount, report.ResultRev, reviewerIndex, reviewErr.Error())
		}
		body = AppendEventSummary(body, errSummary)
		_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
			Kind:      "review-manual-required",
			Summary:   class,
			Body:      body,
			Actor:     in.Assignee,
			Source:    "ddx work",
			CreatedAt: now().UTC(),
		})
		applyReviewOperatorRequiredParking(
			in.Store,
			in.Bead.ID,
			in.Assignee,
			now().UTC(),
			"review retry budget exhausted: "+class,
			"review error retry budget requires operator decision",
			"review the pre-close review failure and accept, retry, block, or cancel",
		)
	} else {
		body := ReviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error())
		if slotScoped {
			body = ReviewErrorEventBodyForSlot(class, attemptCount, report.ResultRev, reviewerIndex, reviewErr.Error())
		}
		body = AppendEventSummary(body, errSummary)
		_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
			Kind:      "review-error",
			Summary:   class,
			Body:      body,
			Actor:     in.Assignee,
			Source:    "ddx work",
			CreatedAt: now().UTC(),
		})
	}
	if reviewRes != nil {
		report.ReviewVerdict = string(reviewRes.Verdict)
		report.ReviewRationale = reviewRes.Rationale
	}
	report.Status = ExecuteBeadStatusReviewMalfunction
	report.Detail = "pre-close review: " + class
	out.Report = report
	out.Approved = false
	chargeReviewCost()
	return out
}

report.ReviewVerdict = string(reviewRes.Verdict)
report.ReviewRationale = reviewRes.Rationale
artifactPath, artifactErr := PersistReviewerStream(in.ProjectRoot, in.Bead.ID, report.AttemptID, reviewRes.RawOutput)
if artifactErr != nil && in.Log != nil {
	_, _ = fmt.Fprintf(in.Log, "reviewer stream artifact: %v\n", artifactErr)
}

reviewSummary := EventBodySummary{
	Harness:     reviewRes.ReviewerHarness,
	Model:       reviewRes.ReviewerModel,
	InputBytes:  reviewRes.InputBytes,
	OutputBytes: reviewRes.OutputBytes,
	ElapsedMS:   reviewRes.DurationMS,
}
reviewBudgetExceeded := chargeReviewCost()
switch reviewRes.Verdict {
case VerdictApprove:
	// Approved: record the verdict event and then close. The close must
	// land AFTER the review event so the gate sees the terminal verdict.
	_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
		Kind:      "review",
		Summary:   "APPROVE",
		Body:      AppendEventSummary(ReviewEventBody("APPROVE", reviewRes.Rationale, artifactPath), reviewSummary),
		Actor:     in.Assignee,
		Source:    "ddx work",
		CreatedAt: now().UTC(),
	})
	if reviewBudgetExceeded {
		// Reviewer cost tripped the budget cap; leave bead open so the
		// loop's BudgetStop can stop the drain before the next claim.
		out.Report = report
		out.Approved = false
		return out
	}
	if cerr := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); cerr != nil {
		out.Report = report
		out.StoreErrOp = "CloseWithEvidence"
		out.StoreErr = cerr
		return out
	}
case VerdictRequestChanges:
	_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
		Kind:      "review",
		Summary:   "REQUEST_CHANGES",
		Body:      AppendEventSummary(ReviewEventBody("REQUEST_CHANGES", reviewRes.Rationale, artifactPath), reviewSummary),
		Actor:     in.Assignee,
		Source:    "ddx work",
		CreatedAt: now().UTC(),
	})
	report.Status = ExecuteBeadStatusReviewRequestChanges
	report.Detail = "pre-close review: REQUEST_CHANGES"
	out.Approved = false
case VerdictBlock:
	rationale := strings.TrimSpace(reviewRes.Rationale)
	classification := ClassifyReviewFindings(reviewRes)
	if rationale == "" && len(classification.Evidence) == 0 {
		_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
			Kind:      "review-malfunction",
			Summary:   "BLOCK without rationale",
			Body:      AppendEventSummary(ReviewEventBody("BLOCK without rationale", "", artifactPath), reviewSummary),
			Actor:     in.Assignee,
			Source:    "ddx work",
			CreatedAt: now().UTC(),
		})
		report.Status = ExecuteBeadStatusReviewMalfunction
		report.Detail = "pre-close review: malformed BLOCK verdict (missing rationale)"
		report.ReviewRationale = ""
		out.Report = report
		out.Approved = false
		return out
	}
	_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
		Kind:      "review",
		Summary:   "BLOCK",
		Body:      AppendEventSummary(rationale, reviewSummary),
		Actor:     in.Assignee,
		Source:    "ddx work",
		CreatedAt: now().UTC(),
	})
	if classification.Class == ReviewFindingClassMalfunction {
		_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
			Kind:      "review-malfunction",
			Summary:   ReviewFindingClassMalfunction,
			Body:      AppendEventSummary(classification.Reason, reviewSummary),
			Actor:     in.Assignee,
			Source:    "ddx work",
			CreatedAt: now().UTC(),
		})
		report.Status = ExecuteBeadStatusReviewMalfunction
		report.Detail = "pre-close review: " + ReviewFindingClassMalfunction
		out.Report = report
		out.Approved = false
		return out
	}
	if terminalClass := classifyTerminalReviewBlock(reviewRes); terminalClass != "" {
		events, _ := in.Store.Events(in.Bead.ID)
		applyTerminalReviewBlock(in.Store, in.Bead.ID, in.Assignee, now().UTC(), terminalClass, report.ResultRev, events)
		report.Status = ExecuteBeadStatusReviewTerminalBlock
		report.Detail = "pre-close review: terminal " + terminalClass
		out.Report = report
		out.Approved = false
		return out
	}
	// Non-terminal BLOCK: schedule one bounded repair cycle (review_fixable_gap).
	// If a repair cycle has already been scheduled for this result_rev, fall
	// through to the regular BLOCK triage path so the policy cannot loop.
	if classification.AutomatedRepairEligible && !hasReviewFixableGapRepairScheduled(in.Store, in.Bead.ID, report.ResultRev) {
		groupID := ""
		if reviewGroup != nil {
			groupID = reviewGroup.Bundle.GroupID
		}
		repairCtx := scheduleReviewFixableGapRepair(
			in.Store, in.Bead.ID, in.Assignee, now().UTC(),
			groupID, report.ResultRev,
			strings.TrimSpace(reviewRes.Rationale),
			report.ActualPower,
		)
		report.Status = ExecuteBeadStatusReviewFixableGap
		report.Detail = "pre-close review: review_fixable_gap"
		out.Report = report
		out.Approved = false
		out.RepairContext = repairCtx
		return out
	}
	report.Status = ExecuteBeadStatusReviewBlock
	report.Detail = "pre-close review: BLOCK (flagged for human)"
	out.Approved = false

package agent

import "strings"

const (
	ReviewFindingClassFixableGap  = "review_fixable_gap"
	ReviewFindingClassMalfunction = "review_malfunction"
)

// ReviewFindingClassification is the strict retry/manual class derived from
// structured review evidence. Rationale is retained for operator context, but
// freeform rationale alone is not evidence and cannot make a result repairable.
type ReviewFindingClassification struct {
	Class                   string
	Evidence                []string
	AutomatedRepairEligible bool
	Reason                  string
}

// ClassifyReviewFindings maps a structured reviewer result to the FEAT-010
// review classes used as the policy boundary before repair or manual routing.
func ClassifyReviewFindings(res *ReviewResult) ReviewFindingClassification {
	if res == nil {
		return reviewClassification(ReviewFindingClassMalfunction, nil, "missing review result", false)
	}

	switch res.Verdict {
	case VerdictApprove, VerdictRequestClarification:
		return ReviewFindingClassification{}
	case VerdictRequestChanges, VerdictBlock:
	default:
		return reviewClassification(ReviewFindingClassMalfunction, nil, "malformed review verdict", false)
	}

	evidence := reviewStructuredEvidence(res)
	if len(evidence) == 0 {
		return reviewClassification(ReviewFindingClassMalfunction, nil, "review lacks structured findings or per-AC evidence", false)
	}

	text := strings.ToLower(strings.Join(evidence, "\n"))
	switch {
	case containsAny(text, ReviewTerminalClassUnsafeOrOutScope, "unsafe", "out of scope", "out-of-scope", "outside scope", "non-scope", "forbidden", "scope change", "destructive"):
		return reviewClassification(ReviewTerminalClassUnsafeOrOutScope, evidence, "", false)
	case containsAny(text, ReviewTerminalClassTooLarge, "too large", "too broad", "decompose", "split this bead", "split the bead", "needs decomposition"):
		return reviewClassification(ReviewTerminalClassTooLarge, evidence, "", false)
	case containsAny(text, ReviewTerminalClassSpecGap, "spec gap", "specification gap", "contradictory", "contradiction", "ambiguous requirement", "requirements are unclear", "unclear requirement"):
		return reviewClassification(ReviewTerminalClassSpecGap, evidence, "", false)
	case containsAny(text, ReviewTerminalClassMissingAcceptance, "missing acceptance", "acceptance criteria missing", "acceptance criterion missing", "unverifiable acceptance", "acceptance is unverifiable"):
		return reviewClassification(ReviewTerminalClassMissingAcceptance, evidence, "", false)
	default:
		return reviewClassification(ReviewFindingClassFixableGap, evidence, "", true)
	}
}

func reviewClassification(class string, evidence []string, reason string, repair bool) ReviewFindingClassification {
	return ReviewFindingClassification{
		Class:                   class,
		Evidence:                append([]string(nil), evidence...),
		AutomatedRepairEligible: repair,
		Reason:                  strings.TrimSpace(reason),
	}
}

func reviewStructuredEvidence(res *ReviewResult) []string {
	if res == nil {
		return nil
	}
	var evidence []string
	for _, ac := range res.PerAC {
		if strings.TrimSpace(ac.Evidence) == "" {
			continue
		}
		parts := []string{ac.Item, ac.Grade, ac.Evidence}
		line := strings.TrimSpace(strings.Join(parts, " "))
		if line != "" {
			evidence = append(evidence, line)
		}
	}
	for _, finding := range res.Findings {
		summary := strings.TrimSpace(finding.Summary)
		if summary == "" {
			continue
		}
		if loc := strings.TrimSpace(finding.Location); loc != "" {
			summary = loc + ": " + summary
		}
		if sev := strings.TrimSpace(finding.Severity); sev != "" {
			summary = sev + ": " + summary
		}
		evidence = append(evidence, summary)
	}
	return evidence
}

