type loopPhaseEmitter struct {
	progressCh chan<- ProgressEvent
	emit       func(string, map[string]any)
	workerID   string
	projectID  string
	harness    string
	model      string
	profile    string
	runStart   time.Time
	now        func() time.Time
	phaseSeq   *int
}

func newLoopPhaseEmitter(runtime ExecuteBeadLoopRuntime, harness, model, profile string, runStart time.Time, now func() time.Time, phaseSeq *int, emit func(string, map[string]any)) *loopPhaseEmitter {
	if now == nil {
		now = time.Now
	}
	return &loopPhaseEmitter{
		progressCh: runtime.ProgressCh,
		emit:       emit,
		workerID:   runtime.WorkerID,
		projectID:  runtime.ProjectRoot,
		harness:    harness,
		model:      model,
		profile:    profile,
		runStart:   runStart,
		now:        now,
		phaseSeq:   phaseSeq,
	}
}

func (e *loopPhaseEmitter) EmitProgress(_ context.Context, beadID string, phase work.Phase, outcome work.Outcome) error {
	if e == nil {
		return nil
	}
	phaseSeq := e.nextPhaseSeq()
	progressPhase := string(phase)
	if phase == work.PhaseTerminal {
		progressPhase = terminalProgressPhase(outcome)
	}
	evt := newProgressEvent(
		e.workerID,
		e.projectID,
		beadID,
		outcome.AttemptID,
		e.harness,
		e.model,
		e.profile,
		progressPhase,
		phaseSeq,
		false,
		e.now().Sub(e.runStart).Milliseconds(),
	)
	evt.TS = e.now().UTC()
	evt.Message = outcome.Detail
	emitProgress(e.progressCh, evt)
	return nil
}

func (e *loopPhaseEmitter) EmitResult(_ context.Context, beadID string, outcome work.Outcome) error {
	if e == nil || e.emit == nil {
		return nil
	}
	durationMS := outcome.DurationMS
	if durationMS == 0 {
		durationMS = e.now().Sub(e.runStart).Milliseconds()
	}
	e.emit("bead.result", map[string]any{
		"bead_id":              beadID,
		"status":               outcome.Status,
		"detail":               outcome.Detail,
		"session_id":           outcome.SessionID,
		"result_rev":           outcome.ResultRev,
		"base_rev":             outcome.BaseRev,
		"preserve_ref":         outcome.PreserveRef,
		"no_changes_rationale": outcome.NoChangesRationale,
		"duration_ms":          durationMS,
	})
	return nil
}

func (e *loopPhaseEmitter) nextPhaseSeq() int {
	if e == nil || e.phaseSeq == nil {
		return 0
	}
	*e.phaseSeq = *e.phaseSeq + 1
	return *e.phaseSeq
}

func terminalProgressPhase(outcome work.Outcome) string {
	switch outcome.Status {
	case ExecuteBeadStatusSuccess, ExecuteBeadStatusAlreadySatisfied:
		return "done"
	default:
		if outcome.PreserveRef != "" {
			return "preserved"
		}
		return "failed"
	}
}

func phaseOutcomeFromReport(report ExecuteBeadReport, attemptID string, durationMS int64) work.Outcome {
	return work.Outcome{
		AttemptID:          attemptID,
		Status:             report.Status,
		Detail:             report.Detail,
		SessionID:          report.SessionID,
		ResultRev:          report.ResultRev,
		BaseRev:            report.BaseRev,
		PreserveRef:        report.PreserveRef,
		NoChangesRationale: report.NoChangesRationale,
		DurationMS:         durationMS,
	}
}

func phaseOutcomeFromAttemptOut(report ExecuteBeadReport, attemptOut agenttry.Outcome, attemptID string, durationMS int64) work.Outcome {
	outcome := phaseOutcomeFromReport(report, attemptID, durationMS)
	outcome.Disposition = string(attemptOut.Disposition)
	if attemptOut.Parking != nil && attemptOut.Parking.Event != nil {
		outcome.ParkReason = attemptOut.Parking.Event.Kind
	}
	return outcome
}

func applyProviderConnectivityRouteExclusion(
	store ExecuteBeadLoopStore,
	beadID string,
	actor string,
	report ExecuteBeadReport,
	operatorPinned bool,
	nextFloorFn func(int) (int, error),
	at time.Time,
) error {
	var (
		repeatFailure bool
		repeatCount   int
	)
	endpoint, timeoutClass := parseProviderConnectivityFacts(report)
	if err := store.Update(context.Background(), beadID, func(b *bead.Bead) {
		existing := readFailedRoutes(b.Extra)
		for _, e := range existing {
			if e.Provider == report.Provider && e.Model == report.Model {
				repeatFailure = true
				repeatCount = e.Count + 1
				break
			}
		}
		appendFailedRoute(b, FailedRouteEntry{
			Provider:     report.Provider,
			Model:        report.Model,
			ActualPower:  report.ActualPower,
			Reason:       FailureModeProviderConnectivity,
			Endpoint:     endpoint,
			TimeoutClass: timeoutClass,
			At:           at.UTC().Format(time.RFC3339),
		})
	}); err != nil {
		return err
	}
	if repeatFailure {
		body, _ := json.Marshal(map[string]any{
			"provider":      report.Provider,
			"model":         report.Model,
			"actual_power":  report.ActualPower,
			"count":         repeatCount,
			"reason":        FailureModeProviderConnectivity,
			"endpoint":      endpoint,
			"timeout_class": timeoutClass,
			"action":        "keep_open_for_autonomous_retry",
		})
		_ = store.AppendEvent(beadID, bead.BeadEvent{
			Kind:      "provider_connectivity.auto_retry",
			Summary:   "repeated provider connectivity failure kept open for autonomous retry",
			Body:      string(body),
			Actor:     actor,
			Source:    "ddx work",
			CreatedAt: at,
		})
	}
	return nil
}

func autoReopenRetryableProviderConnectivityProposals(
	ctx context.Context,
	store ExecuteBeadLoopStore,
	actor string,
	at time.Time,
	emit func(string, map[string]any),
) (int, error) {
	if err := ctx.Err(); err != nil {
		return 0, err
	}
	proposedStore, ok := store.(proposedOperatorAttentionStore)
	if !ok {
		return 0, nil
	}
	proposed, err := proposedStore.ProposedOperatorAttention()
	if err != nil {
		return 0, err
	}
	var reopened int
	for _, b := range proposed {
		if !isRetryableProviderConnectivityProposal(b) {
			continue
		}
		if err := store.UpdateWithLifecycleStatus(b.ID, bead.StatusOpen, bead.LifecycleTransitionOptions{
			Reason: "provider connectivity failure is retryable route evidence; reopening for autonomous fallback",
			Source: "ddx work",
			Actor:  actor,
		}, func(b *bead.Bead) error {
			ensureBeadExtra(b)
			b.Labels = removeBeadLabels(b.Labels, bead.LabelNeedsHuman, bead.LabelNeedsInvestigation)
			bead.SetNeedsHumanMeta(b, bead.NeedsHumanMeta{})
			return nil
		}); err != nil {
			return reopened, err
		}
		body, _ := json.Marshal(map[string]any{
			"reason": "provider_connectivity",
			"action": "reopen_for_autonomous_retry",
		})
		_ = store.AppendEvent(b.ID, bead.BeadEvent{
			Kind:      "provider_connectivity.auto_reopen",
			Summary:   "reopened provider-connectivity operator-attention bead for autonomous retry",
			Body:      string(body),
			Actor:     actor,
			Source:    "ddx work",
			CreatedAt: at,
		})
		if emit != nil {
			emit("provider_connectivity.auto_reopen", map[string]any{
				"bead_id": b.ID,
				"reason":  "provider_connectivity",
			})
		}
		reopened++
	}
	return reopened, nil
}

func isRetryableProviderConnectivityProposal(b bead.Bead) bool {
	if b.Status != bead.StatusProposed {
		return false
	}
	meta := bead.GetNeedsHumanMeta(b)
	text := strings.ToLower(strings.Join([]string{
		meta.Reason,
		meta.Summary,
		meta.SuggestedAction,
		meta.Source,
	}, "\n"))
	if !strings.Contains(text, "provider") {
		return false
	}
	return strings.Contains(text, "provider_connectivity") ||
		strings.Contains(text, "provider unreachable") ||
		strings.Contains(text, "unreachable on 2+ attempts") ||
		strings.Contains(text, "connectivity")
}

// emitEscalationAbortedEvent records a kind=execution-escalation-aborted event
// when nextFloorFn returns an error (typically ErrLadderExhausted). Best-effort.
func emitEscalationAbortedEvent(store BeadEventAppender, beadID, actor, provider, model string, actualPower int, at time.Time) {
	if store == nil || beadID == "" {
		return
	}
	summary := fmt.Sprintf("escalation aborted: ladder exhausted at power %d provider=%s", actualPower, provider)
	if model != "" {
		summary += " model=" + model
	}
	appendWorkEvent(store, beadID, "execution-escalation-aborted", summary, map[string]any{
		"provider":     provider,
		"model":        model,
		"actual_power": actualPower,
		"reason":       fmt.Sprintf("ladder exhausted at power %d", actualPower),
	}, actor, at)
}

// emitRouteFailureEvent records a kind=route-failure event capturing the
// failed (provider, model) tuple and the surface error. Best-effort.
func emitRouteFailureEvent(store BeadEventAppender, beadID, actor string, report ExecuteBeadReport, at time.Time) {
	if store == nil || beadID == "" {
		return
	}
	endpoint, timeoutClass := parseProviderConnectivityFacts(report)
	summary := "provider=" + report.Provider
	if report.Model != "" {
		summary += " model=" + report.Model
	}
	if endpoint != "" {
		summary += " endpoint=" + endpoint
	}
	if timeoutClass != "" {
		summary += " (" + timeoutClass + ")"
	}
	summary += " connectivity failure"
	appendWorkEvent(store, beadID, "route-failure", summary, map[string]any{
		"provider":       report.Provider,
		"model":          report.Model,
		"harness":        report.Harness,
		"actual_power":   report.ActualPower,
		"endpoint":       endpoint,
		"timeout_class":  timeoutClass,
		"detail":         report.Detail,
		"error":          report.Error,
		"outcome_reason": FailureModeProviderConnectivity,
	}, actor, at)
}

func isRoutingInfrastructureReport(report ExecuteBeadReport) bool {
	if report.Status != ExecuteBeadStatusExecutionFailed {
		return false
	}
	combined := strings.TrimSpace(strings.Join([]string{
		report.Detail,
		report.Error,
		report.Stderr,
	}, "\n"))
	if combined == "" {
		return false
	}
	lower := strings.ToLower(combined)
	return containsAny(lower,
		"resolveroute:",
		"no viable routing candidate",
		"no live provider supports",
		"no candidate satisfying local endpoint")
}

