// maxReviewerEventBody is the hard cap on bytes written to an event body for
// a reviewer verdict event. Full streams persist as a sidecar artifact; the
// body holds a summary plus the artifact path. 512 bytes fits a verdict name,
// one line of rationale, and a path without blowing the bead event envelope
// or tipping us toward bd's 65,535-byte per-field cap.
const maxReviewerEventBody = 512

// PersistReviewerStream writes the full reviewer raw output to an artifact
// sidecar under the project's execution evidence tree. Returns the relative
// path (from projectRoot) on success, empty string plus error on failure.
//
// The sidecar path shape is
// `.ddx/executions/<attemptID>/reviewer-stream.log` when attemptID is
// available; otherwise a timestamped fallback under
// `.ddx/executions/reviewer-streams/` keeps streams grouped even without a
// corresponding bundle. The caller is responsible for not losing the stream
// when this returns a non-nil error — log but do not drop the verdict.
func PersistReviewerStream(projectRoot, beadID, attemptID, fullStream string) (string, error) {
	if projectRoot == "" {
		return "", fmt.Errorf("reviewer stream artifact: empty projectRoot")
	}
	if fullStream == "" {
		return "", nil
	}

	var dir, filename string
	var rel string
	if attemptID != "" {
		dir = ddxroot.JoinProject(projectRoot, "executions", attemptID)
		filename = "reviewer-stream.log"
		rel = ddxroot.JoinRelative("executions", attemptID, filename)
	} else {
		dir = ddxroot.JoinProject(projectRoot, "executions", "reviewer-streams")
		ts := time.Now().UTC().Format("20060102T150405")
		bid := beadID
		if bid == "" {
			bid = "unknown"
		}
		filename = ts + "-" + bid + ".log"
		rel = ddxroot.JoinRelative("executions", "reviewer-streams", filename)
	}

	if err := os.MkdirAll(dir, 0o755); err != nil {
		return "", fmt.Errorf("reviewer stream artifact: mkdir %s: %w", dir, err)
	}
	path := filepath.Join(dir, filename)
	if err := os.WriteFile(path, []byte(fullStream), 0o644); err != nil {
		return "", fmt.Errorf("reviewer stream artifact: write %s: %w", path, err)
	}

	return rel, nil
}

// ReviewEventBody assembles a bounded event body for a reviewer verdict event
// from the verdict label, the rationale (which may be a full review stream),
// and the artifact path where the full stream was persisted. Guarantees the
// returned string is at most maxReviewerEventBody bytes.
//
// Layout:
//
//	<verdict>
//	<first non-empty rationale line, truncated to fit>
//	artifact: <artifactPath>
//
// artifactPath is optional; when absent the layout omits that line.
func ReviewEventBody(verdict, rationale, artifactPath string) string {
	verdict = strings.TrimSpace(verdict)
	rationale = strings.TrimSpace(rationale)
	artifactPath = strings.TrimSpace(artifactPath)

	var firstLine string
	if rationale != "" {
		for _, line := range strings.Split(rationale, "\n") {
			trimmed := strings.TrimSpace(line)
			if trimmed != "" {
				firstLine = trimmed
				break
			}
		}
	}

	var b strings.Builder
	if verdict != "" {
		b.WriteString(verdict)
	}

	artifactLine := ""
	if artifactPath != "" {
		artifactLine = "artifact: " + artifactPath
	}

	// Reserve room for the verdict and the artifact line plus two newlines.
	reserved := b.Len()
	if artifactLine != "" {
		reserved += len("\n") + len(artifactLine)
	}
	budget := maxReviewerEventBody - reserved
	// Account for the newline before the rationale line.
	if firstLine != "" {
		budget -= len("\n")
	}
	if budget < 0 {
		budget = 0
	}

	if firstLine != "" {
		if len(firstLine) > budget {
			// Leave space for a trailing truncation marker.
			const marker = "…"
			if budget > len(marker) {
				firstLine = firstLine[:budget-len(marker)] + marker
			} else {
				firstLine = firstLine[:budget]
			}
		}
		if firstLine != "" {
			b.WriteString("\n")
			b.WriteString(firstLine)
		}
	}

	if artifactLine != "" {
		b.WriteString("\n")
		b.WriteString(artifactLine)
	}

	out := b.String()
	if len(out) > maxReviewerEventBody {

		assert.True(t, ok, "manifest.json must also carry evidence_assembly")
	})

}

// TestReviewEventBodySummary covers FEAT-022 §16: review, review-error, and
// compare-result event bodies all carry the compact summary fields
// (input_bytes, output_bytes, elapsed_ms, harness, model).
func TestReviewEventBodySummary(t *testing.T) {
	summary := EventBodySummary{
		Harness:     "claude",
		Model:       "claude-opus-4-6",
		InputBytes:  12345,
		OutputBytes: 678,
		ElapsedMS:   42,
	}

	t.Run("review", func(t *testing.T) {
		body := AppendEventSummary(ReviewEventBody("APPROVE", "ok", "path/to/log"), summary)
		assertSummaryFields(t, body, summary)
	})

	t.Run("review-error", func(t *testing.T) {
		body := AppendEventSummary(
			ReviewErrorEventBody(evidence.OutcomeReviewTransport, 1, "abc123", "boom"),
			summary,
		)
		assertSummaryFields(t, body, summary)
		// Crucial: section detail does NOT land on the event body.
		assert.NotContains(t, body, "bytes_included",
			"event body must not carry per-section detail (lives only on the artifact)")
	})

}

func assertSummaryFields(t *testing.T, body string, s EventBodySummary) {
	t.Helper()
	assert.Contains(t, body, "harness="+s.Harness)
	assert.Contains(t, body, "model="+s.Model)
	assert.Contains(t, body, "input_bytes=12345")
	assert.Contains(t, body, "output_bytes=678")
	assert.Contains(t, body, "elapsed_ms=42")
}

// TestReviewEventBodyCap covers FEAT-022 §16's cap clause: even with maximum-
// sized summary fields, the event body must still respect the bead store cap
// at cli/internal/bead/store.go:747 (capFieldBytes / MaxFieldBytes = 65535).
func TestReviewEventBodyCap(t *testing.T) {
	storeDir := t.TempDir()
	store := bead.NewStore(storeDir)
	require.NoError(t, store.Init(context.Background()))
	require.NoError(t, store.Create(context.Background(), &bead.Bead{ID: "ddx-cap-1", Title: "cap test"}))

	// Build maximum-sized summary fields. Harness/Model strings of 100KB each
	// alone overshoot the 65,535-byte cap; the cap path inside AppendEvent
	// must clamp via capFieldBytes regardless of caller intent.
	bigStr := strings.Repeat("X", 100*1024)
	summary := EventBodySummary{
		Harness:     bigStr,
		Model:       bigStr,
		InputBytes:  1<<31 - 1,
		OutputBytes: 1<<31 - 1,
		ElapsedMS:   1<<31 - 1,
	}
	bigRationale := strings.Repeat("R", 100*1024)
	body := AppendEventSummary(ReviewEventBody("BLOCK", bigRationale, "log"), summary)

	require.NoError(t, store.AppendEvent("ddx-cap-1", bead.BeadEvent{
		Kind:      "review",
		Summary:   "BLOCK",
		Body:      body,
		CreatedAt: time.Now().UTC(),
	}))

	events, err := store.Events("ddx-cap-1")
	require.NoError(t, err)
	require.NotEmpty(t, events)
	stored := events[len(events)-1]
	assert.LessOrEqual(t, len(stored.Body), bead.MaxFieldBytes,
		"event body must respect MaxFieldBytes after AppendEvent's capFieldBytes")
}

