// updateChecksDisabled reports whether the automatic update check should be
// suppressed. It honors the env var, the persistent --no-update-check flag, and
// a command-local --no-check flag (e.g. on `ddx version`) when present.
func updateChecksDisabled(cmd *cobra.Command) bool {
	if os.Getenv("DDX_DISABLE_UPDATE_CHECK") == "1" {
		return true
	}
	if v, err := cmd.Flags().GetBool("no-update-check"); err == nil && v {
		return true
	}
	if v, err := cmd.Flags().GetBool("no-check"); err == nil && v {
		return true
	}
	return false
}

// checkForUpdates performs automatic update check (synchronous, once per 24h)
func (f *CommandFactory) checkForUpdates(cmd *cobra.Command) {
	// Skip if disabled via env var, --no-update-check, or a local --no-check.
	if updateChecksDisabled(cmd) {
		return
	}

	// Load config
	cfg, err := config.Load()
	if err != nil {
		// Silent failure - use defaults
		cfg = config.DefaultNewConfig()
	}

	// Check if disabled via config
	if cfg.UpdateCheck != nil && !cfg.UpdateCheck.Enabled {
		return
	}

	// Create checker and perform check (synchronous)
	checker := update.NewChecker(f.Version, cfg)
	f.updateMu.Lock()
	f.updateChecker = checker
	f.updateDone = make(chan struct{})
	done := f.updateDone
	f.updateMu.Unlock()

	// Run the check asynchronously so command startup is never blocked.
	go func() {
		defer close(done)
		_, _ = checker.CheckForUpdate(context.Background())
		// Also refresh plugin version cache while we have a network call in flight.
		f.refreshPluginVersionCache()
	}()
}

// displayUpdateNotification shows update notification if available
func (f *CommandFactory) displayUpdateNotification(cmd *cobra.Command) error {
	// Skip if disabled via env var, --no-update-check, or a local --no-check.
	if updateChecksDisabled(cmd) {
		return nil
	}

	f.updateMu.Lock()
	checker := f.updateChecker
	done := f.updateDone
	f.updateMu.Unlock()

	if checker == nil {
		return nil
	}

	repoDir := f.WorkingDir
	if repoDir == "" {
		repoDir = "."
	}

	if isFullCommitSHA(commitSHA) && !gitpkg.IsRepository(repoDir) {
		return commitSHA, nil
	}

	cmd := gitpkg.Command(ctx, repoDir, "rev-parse", "--verify", commitSHA+"^{commit}")
	out, err := cmd.Output()
	if err != nil {
		return "", fmt.Errorf("git rev-parse %s: %w", commitSHA, err)
	}
	return strings.TrimSpace(string(out)), nil
}

func isFullCommitSHA(commitSHA string) bool {
	if len(commitSHA) != 40 {
		return false
	}
	for i := 0; i < len(commitSHA); i++ {
		c := commitSHA[i]
		if c >= '0' && c <= '9' {
			continue
		}
		if c >= 'a' && c <= 'f' {
			continue
		}
		if c >= 'A' && c <= 'F' {
			continue
		}
		return false
	}
	return true
}

func (f *CommandFactory) resolveClosingCommitSHA(commitSHA string) (string, error) {
	normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
	if err != nil {
		return "", fmt.Errorf("invalid closing_commit_sha %q: %w", commitSHA, err)
	}
	if normalizedCommitSHA == "" {
		return "", fmt.Errorf("invalid closing_commit_sha %q: empty value", commitSHA)
	}
	return normalizedCommitSHA, nil
}

// commitIsMetadataOnlyTrackerBackfill reports whether the given commit changed
// only bead tracker state. Closing provenance is suppressed only for pure
// tracker backfills that touch .ddx/beads.jsonl and nothing else.
func (f *CommandFactory) commitIsMetadataOnlyTrackerBackfill(commitSHA string) bool {
	if commitSHA == "" {
		return false
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	cmd := gitpkg.Command(ctx, f.WorkingDir, "show", "--pretty=format:", "--name-only", commitSHA)
	out, err := cmd.Output()
	if err != nil {
		return false
	}

	for _, line := range strings.Split(string(out), "\n") {
		path := strings.TrimSpace(line)
		if path == "" {
			continue
		}
		if path != ".ddx/beads.jsonl" {
			return false
		}
	}

	return true
}

func isReviewCloseBead(b *bead.Bead) bool {
	if b == nil {
		return false
	}
	for _, label := range b.Labels {
		switch label {
		case "action:review", "kind:review", "phase:review", "review-finding":
			return true
		}
	}
	return false
}

